module top_module(
    input clk,
    input rst,
    input ld,
    input si,
    output so,
    output reg [3:0] q
);always @(posedge clk) begin
        if (rst) begin
            q <= 4'b0;
        end else if (ld) begin
            q <= si;
        end else begin
            q <= {q[2:0], si};
        end
    end

    wire not_q = q[3];
    assign so = not_q;

endmodule
